export interface ArticleCategory { id: string; name: string }

export const ARTICLE_CATEGORIES: ArticleCategory[] = [
  { id: "seo-and-authority", name: "SEO & Authority" },
  { id: "buying-and-evaluation", name: "Buying & Evaluation" },
  { id: "branding", name: "Branding & Naming" },
  { id: "investing-and-flipping", name: "Investing & Flipping" },
  { id: "startups", name: "Startups & Founders" },
  { id: "ecommerce-and-retail", name: "Ecommerce & Retail" },
  { id: "local-and-services", name: "Local & Services" },
  { id: "creators-and-media", name: "Creators & Media" },
  { id: "industries-and-niches", name: "Industries & Niches" },
  { id: "regional-markets", name: "Regional Markets" },
  { id: "strategy-and-roi", name: "Strategy & ROI" },
  { id: "buyer-guides", name: "Buyer Guides" }
];

// Tokenise keyword + h1 into terms (>=4 chars, no stopwords) for related-articles scoring.
const STOP = new Set(["the","and","for","with","that","this","your","from","into","what","when","where","which","while","than","then","more","most","over","under","best","good","make","made","does","done","still","just","like","they","them","there","these","those","have","will","would","could","should","really","very","also","such","each","because","about","after","before","through","across","into","upon","onto","without","within","between","being","still","keep","give","take","only","once","much","many","some","every","other","another","sites","site","name","names","domain","domains","premium","expired","com","ai","seo","com.","com,"]);

function terms(text: string): string[] {
  return text
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, " ")
    .split(/\s+/)
    .filter((w) => w.length >= 4 && !STOP.has(w));
}

const TERMS_CACHE: Record<string, string[]> = {};
function getTerms(slug: string): string[] {
  if (!TERMS_CACHE[slug]) {
    const m = ARTICLE_META[slug];
    TERMS_CACHE[slug] = m ? Array.from(new Set(terms(m.h1 + " " + m.primaryKeyword + " " + m.metaDescription))) : [];
  }
  return TERMS_CACHE[slug];
}

export function getRelatedArticles(slug: string, limit = 6): ArticleMeta[] {
  const me = ARTICLE_META[slug];
  if (!me) return [];
  const myTerms = new Set(getTerms(slug));
  const scores: Array<{ slug: string; score: number }> = [];
  for (const other of ARTICLE_SLUGS) {
    if (other === slug) continue;
    const o = ARTICLE_META[other];
    if (!o) continue;
    const otherTerms = getTerms(other);
    let s = 0;
    for (const t of otherTerms) if (myTerms.has(t)) s += 1;
    if (o.categoryId === me.categoryId) s += 4;
    if (s > 0) scores.push({ slug: other, score: s });
  }
  scores.sort((a, b) => b.score - a.score);
  return scores.slice(0, limit).map((s) => ARTICLE_META[s.slug]);
}

export function getArticlesByCategory(categoryId: string): ArticleMeta[] {
  return ARTICLE_SLUGS.map((s) => ARTICLE_META[s]).filter((a) => a.categoryId === categoryId);
}
